425	  /**
426	   * VIE-04: client-only temporary visibility override scoped to one view.
427	   * `mode: 'isolate'` shows only the listed categories / element ids;
428	   * `mode: 'hide'` hides them. Cleared on view change or explicit reset;
429	   * never persisted.
430	   */
431	  temporaryVisibility: TemporaryVisibility | null;
432	  setTemporaryVisibility: (next: TemporaryVisibility | null) => void;
433	  clearTemporaryVisibility: () => void;
434	  /** SKB-23 — set/clear the per-phase preview filter. */
435	  setViewerPhaseFilter: (next: { phases: string[]; includeUntagged: boolean } | null) => void;
436	  clearViewerPhaseFilter: () => void;
