438	  setActivity: (e: ActivityEvent[]) => void;
439	  setIdentity: (userId: string, display: string, peerId: string) => void;
440	};
441	
442	export type TemporaryVisibilityMode = 'isolate' | 'hide';
443	
444	export type TemporaryVisibility = {
445	  /** plan_view, viewpoint, or other view scope this override is bound to. */
446	  viewId: string;
447	  mode: TemporaryVisibilityMode;
448	  /** Element kinds (`wall`, `door`, …) covered by the override. */
449	  categories: string[];
450	  /** Specific element ids covered by the override. */
451	  elementIds?: string[];
452	};
453	
454	/**
455	 * VIE-04: returns true when an element of `kind` should be drawn under the
456	 * given temporary-visibility override. Pass `null` when there's no override
457	 * active — the helper short-circuits to "visible".
458	 */
459	export function isElementVisibleUnderTemporaryVisibility(
460	  kind: string,
461	  override: TemporaryVisibility | null,
462	  elementId?: string,
463	): boolean {
464	  if (override === null) return true;
465	  const inCategorySet = override.categories.includes(kind);
466	  const inElementSet = elementId ? (override.elementIds ?? []).includes(elementId) : false;
467	  const inSet = inCategorySet || inElementSet;
468	  return override.mode === 'isolate' ? inSet : !inSet;
469	}
